var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨, 이건 어때요? 그럴싸하게 생기지 않았어요?","JPN":"ラッシュフォードさん、これはどうですか？　それっぽくないですか？","ENG":"Miss Rashford, what about this? It kind of looks like a relic, no?","TWN":"雷斯福特，這個怎麼樣？不覺得很像嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"글쎄요. 그냥 불에 녹은 냄비로 보입니다만.","JPN":"どうでしょう。ただ火で溶けた鍋にしか見えませんが。","ENG":"Hmm... It just looks like a melted pot to me.","TWN":"這個嘛，看起來像是被火融化的鍋子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"그러면 이건요?","JPN":"じゃあ、これは？","ENG":"Then what about this one?","TWN":"那這個呢？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아무리 그래도 밑창 떨어진 구두가 성유물일 것 같진 않군요.","JPN":"いくらなんでも底の抜けた靴が聖遺物ではないでしょう。","ENG":"I don't see how the sole of a shoe can be a Holy Relic.","TWN":"再怎麼說，鞋底壞掉的皮鞋應該不會是聖遺物吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"휴우……. 어떻게 생겼는지도 모르니까 찾기가 쉽지 않네요.","JPN":"ふう……どんな形をしてるのかわからないから、探すのに苦労しますね。","ENG":"*Sigh...* It's difficult to find something when we don't know what it's supposed to look like.","TWN":"呼……又不知道長什麼樣，是要怎麼找啦！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"여기 쌓여 있는 돌무더기나 나뭇가지 중 하나가 성유물이면 어쩌죠?","JPN":"ここに積もってる石ころとか木の枝一本が聖遺物だったらどうしましょう？","ENG":"What if it's one of these rocks or twigs piled up here?","TWN":"要這堆石頭或樹枝中，有一個是聖遺物的話怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관, 혹시 성유물의 생김새에 대해 짐작가는 바가 없나?","JPN":"指揮官、聖遺物の外見について思い当たることはないか？","ENG":"Commander. Can you remember anything about what the Holy Relic looks like?","TWN":"指揮官，你對於聖遺物的外觀有什麼想法嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"죄송합니다. 지금으로선 아무런 단서도 떠오르지 않는군요.","JPN":"申し訳ありません。現時点ではなんの手がかりも思い浮びませんね。","ENG":"Sorry. Nothing comes to mind right now.","TWN":"對不起，我現在一點頭緒都沒有。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런가. 하긴 괜한 질문이었군.","JPN":"そうか。まあ、余計な質問だったか。","ENG":"I see. Forget that I asked.","TWN":"是嗎？也是，我不該問你的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어라? 래시포드 씨, 그걸 왜 지휘관님에게 물어보세요?","JPN":"あれ？　ラッシュフォードさん、どうしてそれを指揮官に聞くんですか？","ENG":"Huh? Miss Rashford? Why did you ask that to the Commander?","TWN":"嗯？雷斯福特，你為什麼問指揮官？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아, 별거 아닙니다. 머리를 맞대고 고민해 보면 참신한 발상이 떠오를지도 모르니까요.","JPN":"あ、大したことではありません。額を集めて悩んでみると、斬新なアイデアが浮かび上がるかもしれませんから。","ENG":"Oh, it's nothing. I was just thinking that if we put our heads together we might get an idea.","TWN":"喔，沒什麼，想說彼此腦力激盪的話，或許會有什麼新的想法。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"앗, 그렇네요!","JPN":"あっ、そうですね！","ENG":"Oh, I see!","TWN":"喔，原來是這樣！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"병사 여러분도 그럴싸한 물건을 발견하면 언제든 말씀해 주세요!","JPN":"兵士のみなさんもそれっぽいものを発見したらいつでも話してください！","ENG":"If you find something that could be the relic, please don't hesitate show us!","TWN":"各位士兵，如果有發現什麼類似的東西，請隨時告訴我！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"이건 어떻습니까?","JPN":"これはどうでしょう？","ENG":"What about this?","TWN":"這個怎麼樣？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어머, 신기하게 생긴 문고리네요.","JPN":"あら、不思議な取っ手ですね。","ENG":"Oh my. That's an odd looking door handle.","TWN":"哇，長得好特別的門把。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"저도 특이하게 생긴 걸 주웠습니다만, 한 번 봐 주시겠습니까?","JPN":"俺も変わった形をしたものを拾いましたが、見てもらえますか？","ENG":"I found this strange thing. Do you think this could be it?","TWN":"我也撿到一個長得很特別的東西，可以看一下嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"으음~ 녹은 못이 뭉쳐서 굳은 것 같은데, 혹시 모르니 그것도 가져가 볼까요?","JPN":"うーん、溶けた釘が集まって固まったもののようですけど、念のためそれも持っていきましょうか？","ENG":"Um... I think that's just a bunch of melted nails, but bring it along just it case.","TWN":"嗯～好像是釘子融化後又結塊的樣子，以防萬一，那個也拿走吧！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"김 빠지는군……. 목숨 걸고 여기까지 와서 하는 게 대책없는 보물찾기라니.","JPN":"力が抜けるな……命をかけてここまで来てやってるのがくだらん宝探しだなんて。","ENG":"This is infuriating... We risked our lives to come here all for a stupid treasure hunt?","TWN":"真沒勁……冒著生命危險來到這裡，結果竟然是毫無頭緒的尋寶遊戲。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"뭐 어때요. 거대한 침식체한테 쫓기는 것보단 낫죠.","JPN":"まあ、いいじゃないですか。巨大な侵食体に追われてるよりはマシでしょう。","ENG":"Look on the bright side. It's way better than getting chased by one of those giant C.O.s.","TWN":"那又怎麼樣，總比被巨大的侵蝕體追好吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"이거 보세요. 반짝거리는 게 혹시 성유물 아닐까요?","JPN":"これを見てください。キラキラしてるし、ひょっとして聖遺物じゃないですかね？","ENG":"Hey, look at that! It's so shiny... Could it be the Holy Relic?","TWN":"你看這個，一閃一閃的，會不會是聖遺物？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"누가 봐도 그냥 구슬이잖아. 어릴 때 구슬치기도 안 해 봤냐?","JPN":"どう見てもただのビー玉だろ。小さい頃ビー玉遊びもしてなかったのか？","ENG":"It's just a marble. Didn't you play with marbles when you were a kid?","TWN":"怎麼看都像彈珠吧，你小時候沒玩過彈珠嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"아, 왜요. 보기엔 그래도 특별한 구슬일 수도 있지.","JPN":"何ですか。見かけはそうでも特別なビー玉かもしれませんよ。","ENG":"Oh, c'mon. Maybe it's a special marble.","TWN":"怎樣？説不定是很特別的珠子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"쳇, 뭘 찾았는지 몰라도 무조건 성유물 아니라고 할 거예요.","JPN":"ちっ、何を見つけたか知りませんが、なんでも聖遺物じゃないって言いますからね。","ENG":"Tch! Whatever you found, I'm going to say that it's not the Holy Relic.","TWN":"嘖，雖然不知道這是什麼，但你一定會說這不是聖遺物。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"성유물이고 자시고가 아니야.","JPN":"聖遺物なんかじゃねえ。","ENG":"It's not.","TWN":"這跟聖遺物沒什麼關係。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"군번줄이다. 저쪽에도 떨어져 있어.","JPN":"認識票だ。あそこにも落ちてるぞ。","ENG":"It's a dog tag. There's more over there.","TWN":"是軍牌，那邊也有。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"잠깐, 저기 반쯤 파묻혀 있는 거 혹시 총이에요?","JPN":"まてよ、あっちに半分くらい埋まってるのって、もしかして銃ですか？","ENG":"Hold on. Is that a half-buried gun over there?","TWN":"等等，那裡面埋著的是槍嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장님!","JPN":"隊長！","ENG":"Captain!","TWN":"隊長！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"무슨 일이지?","JPN":"どうした？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"시신을 찾았습니다! 왕립군 병사들이예요!","JPN":"死体を見つけました！　王立軍の兵士たちです！","ENG":"We found bodies! It's the Royal Army!","TWN":"我們找到皇家軍隊士兵的屍體！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이건, 왕립군 총사대 직속 1번대의 약장……. 복식도 20년 전 왕실에서 사용했던 그대로야.\xA0","JPN":"これは、王立軍銃士隊直属1番隊の略装……服も20年前に王室で使ってたものだね。\xA0","ENG":"That is the service ribbon of the 1st Musketeer Division of the Royal Army... Even the uniform dates back 20 years.\xA0","TWN":"這是皇家射擊隊直屬第1隊的彈匣……穿著也跟二十年前的皇室一樣。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"총사대 1번대…….","JPN":"銃士隊1番隊……","ENG":"The 1st Musketeer Division...","TWN":"射擊隊第1隊……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내가 소속되어 있던 부대가 맞다.","JPN":"私が所属していた部隊で間違いない。","ENG":"There's no doubt I was a member of this unit.","TWN":"是我所屬的部隊沒錯。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 시신들은 마을터에서 멀지 않은 곳에 있었어.","JPN":"この死体は村からそう遠くないところにいた。","ENG":"The corpses are not far off from the village.","TWN":"這些屍體就在離村莊不遠的地方。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아마 이 근방에서 부대가 전멸할 정도로 큰 전투가 벌어진 것 같아.","JPN":"多分この辺りで部隊が全滅するほどの大きな戦闘が起きたようね。","ENG":"It appears that there was a battle large enough to wipe out an entire unit.","TWN":"應該是在這附近有發生過導致全軍覆沒的大規模戰鬥。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그러면 지휘관님이… 정말로 그 총사대장 큐리안이라고요?","JPN":"じゃあ、指揮官が……本当にあの銃士隊長キュリアンなんですか？","ENG":"Then does that mean... He is the real Curian?","TWN":"那指揮官… 真的是那個隊長庫里安嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"맙소사, 촌장님은 정신착란 환자라고 호언장담을 하셨는데……","JPN":"そんな、村長は精神錯乱の患者だとあれほど言っていたのに……","ENG":"Impossible...! The Chief said that he was just a delusional fool...!","TWN":"我的天，村長還說他是精神病患……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 와트 씨는 그럼 지휘관님이 환자라는 걸 알고도 따르던 거네요?","JPN":"へへ、じゃあワットさんは指揮官が患者ってことを知ってて従ってたわけですね？","ENG":"Heh heh, so you followed his orders knowing that the Commander was delusional?","TWN":"嘿嘿，那你明知道指揮官是神經病還跟隨他嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"임마! 그러는 넌 뭐가 아쉬워서 지휘관님이 있는 부대에 자원 입대한 건데?!","JPN":"おい、こら！　そういうお前は何が惜しくて指揮官のいる部隊に志願して入隊したんだ！？","ENG":"Hey! Then what about you, huh? Why'd you join?!","TWN":"這小子！那你又為什麼自願加入指揮官的部隊？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"저요? 저는 저희 지휘관님이 마음에 들어서 지원한 거죠.","JPN":"僕ですか？　僕は指揮官が好きで志願したんですよ。","ENG":"Me? I joined because I like our Commander's style.","TWN":"我嗎？我就是因爲喜歡指揮官才加入的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"지휘관님 얘기가 진짜인지 가짜인지는 딱히 신경 쓴 적 없어요. 와트 씨는 안 그래요?","JPN":"指揮官の話が本当かどうかは特に気にしたことないです。ワットさんは違うんですか？","ENG":"I've never cared whether he's the real Curian or not. Don't you think so, Mr. Watt?","TWN":"我沒有很在意有關指揮官的傳言到底是真是假，華特先生，難道你不是嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"쳇. 위대한 정착자 납셨구만.","JPN":"ちっ。偉い定着者様だな。","ENG":"Tch! Some great settler you are, eh?","TWN":"嘖，偉大的定居者大駕光臨呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그렇다면 정말로…… 제 1 총사대는 성유물을 옮기던 중 누군가의 습격을 받았단 건가?","JPN":"それでは本当に……第1銃士隊は聖遺物を運ぶ途中、何者かに襲われたのか？","ENG":"Then does this mean... that the 1st Musketeer Division was ambushed while they were moving the Holy Relic?","TWN":"難道是……第1射擊隊在搬運聖遺物時，受到某人的偷襲？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"대답해 봐라, 지휘관.","JPN":"答えてみろ、指揮官。","ENG":"Answer the question, Commander.","TWN":"回答我，指揮官。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"대체 그게 뭐였지? 침식체였나? 아니면 사람?","JPN":"それはいったい何だった？　侵食体か？　それとも人間？","ENG":"What attacked you? Was it a C.O.? A person?","TWN":"到底是什麼？是侵蝕體嗎？還是人？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제가 그 날 본 것은…… 침식체도, 사람도 아니었습니다.","JPN":"私があの日見たのは……侵食体でも、人間でもありませんでした。","ENG":"That \\"thing\\" I saw that day... It wasn't a C.O. or a person.","TWN":"我那天看到的……既不是侵蝕體，也不是人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"마치 사람의 탈을 뒤집어쓴 괴물 같았죠.","JPN":"まるで人の仮面を被った化け物のようでした。","ENG":"It was like seeing a monster pretending to be a human.","TWN":"就像一個披著人皮的怪物。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"어중간한 대답으로 넘어갈 문제가 아니다!","JPN":"中途半端な答えで済ませられる問題ではない！","ENG":"This is not the time to play games!","TWN":"這個問題可不用模棱二可的回答就能含糊帶過！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건 국가 적대 세력의 존재 여부를 가르는 중요한 사안이야!","JPN":"これは国家の敵対勢力が存在するかどうかを見分ける重要な事案だ！","ENG":"This is critical in determining whether or not there is a national threat!","TWN":"這是分辨國家敵對勢力存在與否的重要事件！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저도 그 정체는 모릅니다.","JPN":"私もその正体は知りません。","ENG":"I don't know who or what she was.","TWN":"我也不知道她的真正身分。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 홀로 정예 왕실부대를 궤멸시킬 만큼 위험한 힘을 지녔다는 사실만은 확실합니다.","JPN":"ですが、一人で精鋭の王室部隊を壊滅させるほど危険な力を持っているという事実だけは確かです。","ENG":"But I do know that she was strong enough to wipe out an entire group of the Royal Army's elites.","TWN":"但可以肯定的是，她擁有足以毀滅精銳皇家部隊的危險力量。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"알겠다. 이 사안은 돌아가는 대로 보고를 올려야겠군.","JPN":"わかった。この事案は帰り次第報告しなければならないな。","ENG":"I see. I'll report it as such when I get back to the capital.","TWN":"好，這件事回去後必須馬上上報。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지금으로서는 네가 유일한 증인이다. 진상을 밝히기 전까지 절대 죽지 마라, 지휘관.","JPN":"現時点では貴様が唯一の証人だ。真相を明らかにする前に絶対に死ぬな、指揮官。","ENG":"Right now, you are the only witness. Don't you dare think about dying before we get to the bottom of this, Commander.","TWN":"現在看來你是唯一的證人，在查明真相之前絕對不能死，指揮官。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……알겠습니다.","JPN":"……わかりました。","ENG":"Understood.","TWN":"……好的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…방금 그 소리는?","JPN":"……今の音は？","ENG":"Did you hear that?","TWN":"…剛才的聲音是？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨! 탐지기가 다시 작동하기 시작했어요!","JPN":"ラッシュフォードさん！　探知機がまた作動しはじめましたよ！","ENG":"Miss Rashford! The detector started working again!","TWN":"雷斯福特！探測器又開始動咧！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"이게…… 다들 그렇게 찾던 성유물이라고?","JPN":"これが……みんながあんなにも探してた聖遺物だって？","ENG":"Is this... the Holy Relic we were searching for?","TWN":"這……這就是大家一直在找的聖遺物嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"네 의견에 동의하긴 싫지만, 이건 확실히 열쇠처럼 생기진 않았군.","JPN":"お前の意見に同意したくはねえけど、こりゃ確かに鍵には見えないな。","ENG":"I hate to agree with you, but this doesn't look anything like a key.","TWN":"我不想認同你的意見，但這確實長得不像鑰匙。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"탐지기는 이 물건을 가리키고 있어요.","JPN":"探知機はこれを示してますよ。","ENG":"The detector's pointing towards it, though.","TWN":"探測器指著這個東西。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"낙원문의 시그니처 패턴에 반응하는 물건이니 성유물이 틀림없을 거예요.","JPN":"楽園の門のシグネチャーパターンに反応する機械ですから、間違いなく聖遺物でしょう。","ENG":"It's giving off the same signature pattern as Avalon's Gate, so it must be the Holy Relic.","TWN":"這東西對樂園門的信號模式有反應，肯定是聖遺物。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……그런데 왜 여기 남아 있는 걸까요?","JPN":"……でも、どうしてここに残ってるんでしょうね？","ENG":"But why was it just abandoned here?","TWN":"……但是爲什麼還留在這裡呢？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이 참상을 일으킨 자가 성유물을 노리고 있었다면 이렇게 방치했을 리가 없습니다.","JPN":"この惨劇を起こした者が聖遺物を狙っていたなら、こんな風に放置するはずがありません。","ENG":"If whoever caused this catastrophe was after the Holy Relic, then why would she leave without taking it?","TWN":"如果造成如此慘案的人目的是聖遺物，怎麼可能會就這樣置之不理。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"성유물은 허락된 사람 외에는 정체도 알려 주지 않았다잖아요.","JPN":"聖遺物については、許可を与えた人以外には正体も知らせなかったらしいじゃないですか。","ENG":"Wasn't only the person in charge permitted to know what it looked like?","TWN":"除了獲准的人之外，根本沒人知道聖遺物是什麼。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"범인도 막상 어떻게 생겼는지는 몰랐던 거 아닐까요?","JPN":"犯人も結局どんな形なのか知らなかったんじゃないでしょうか？","ENG":"What if the culprit just passed it off as junk?","TWN":"犯人會不會也不知道長什麼樣？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저희는 래시포트 씨의 탐지기 덕분에 찾은 거잖아요.","JPN":"私たちはラッシュフォードさんの探知機のおかげで見つけられたんでしょう。","ENG":"We were only able to find it because of your detector, Miss Rashford.","TWN":"我們是因為有雷斯福特的探測器才能找到的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……그래요. 그 말씀도 일리가 있군요.","JPN":"……そうですね。その言葉も一理あります。","ENG":"Perhaps... That would make sense.","TWN":"……好吧，你這話也有道理。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"우왓! 그럼 지금이 사라졌던 성유물을 되찾은 완전 역사 깊은 순간이란 거네요?","JPN":"うわっ！　じゃあ今、消えてた聖遺物を取り戻した、めっちゃ歴史的な瞬間なわけですね！","ENG":"Whoa! Then this is a historical moment where we finally retrieve the Holy Relic, right?","TWN":"嗚哇！那現在就是找回消失聖遺物的歷史性的一刻嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"장교님! 혹시 우리도 위인전 같은 데 실릴 수 있는 건가요?","JPN":"将校！　もしかしたら僕らも偉人伝とかに載ります？","ENG":"Officer Rashford! Are our names gonna go down in history for this?","TWN":"軍官！我們也會被記載在偉人傳裡嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아서라. 한 것도 없으면서 위인들의 평균치를 깎아내리려고 하지 마.","JPN":"やめとけ。何もやってねえのに偉人の平均値を削るなよ。","ENG":"Enough. Putting your name next to the greats when you haven't done anything will only make them look bad, Peter.","TWN":"你做夢，你明明什麼都沒做，不要拉低偉人的平均值。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 말대로 역사서에 이름이 실릴 정도는 아니다.","JPN":"そのとおり、歴史に名を残すほどのことではない。","ENG":"As he said, this isn't enough to have your names remembered in history books.","TWN":"沒錯，你們的名字還不至於被記入史冊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"하지만 너희들의 공로를 보고해 왕실 훈장과 그에 상응하는 포상을 내려 줄 수는 있겠지.","JPN":"だが、あなたたちの功労を報告し、王室の勲章とそれ相応の褒賞を与えることは可能だろう。","ENG":"However, I can report your contributions so that you all receive a Royal medal as well as monetary compensation.","TWN":"但我可以跟上頭報告你們的功勞，頒發皇家勳章和獎賞給你們。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"물론 그건 이 성유물을 무사히 회수해 간 뒤에 고려하면 될……","JPN":"もちろんそれはこの聖遺物を無事回収した後に考えればいい……","ENG":"Of course, that is only after we safely bring it back to the─","TWN":"不過一切都要等聖遺物順利回收後再……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"위험해!","JPN":"危ない！","ENG":"Watch out!","TWN":"危險！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님, 괜찮으십니까?","JPN":"将校、大丈夫ですか？","ENG":"Are you okay?","TWN":"軍官，你沒事吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"콜록…","JPN":"ゲホッ……","ENG":"*Cough...*","TWN":"咳咳…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"낚아채 준 덕에 살았군.","JPN":"引っ張ってくれたおかげで助かったな。","ENG":"You saved my life.","TWN":"謝謝你救我。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런데 저건… 대체 뭐지?","JPN":"ところであれは……いったい何だ？","ENG":"But... What the hell was that?","TWN":"不過那個…到底是什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식체입니다. 덩치만 큰 대형종은 아닌 것 같군요.","JPN":"侵食体です。図体だけ大きい大型種ではなさそうですね。","ENG":"A C.O. but it has something more than the large size.","TWN":"是侵蝕體，似乎不是只有塊頭大的大型侵蝕體。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"제길… 방금까지만 해도 잠잠했는데 어디서 저런 게 나타난 거야?","JPN":"くそ……さっきまで静かだったのに、どこからあんなものが現れたんだ？","ENG":"Dammit...! Where the hell did that thing even come from?!","TWN":"可惡，剛才還很平靜，那東西是從哪裡來的？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"피터! 피해 상황은?","JPN":"ピーター、被害状況は？","ENG":"Peter! Status report!","TWN":"彼得！災情如何？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"바위 파편에 맞아 다친 사람들이 있지만 중상자는 없습니다!","JPN":"岩の破片に当たって怪我をした者がいますが、重傷者はいません！","ENG":"Some were grazed by the rock debris, but there are no serious injuries, sir!","TWN":"有人被碎石砸中受傷，但傷勢不重！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"전원 대열 정비!","JPN":"総員隊列を整備！","ENG":"Men, get into formation!","TWN":"全員維持隊形！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"타깃은 전방에 출몰한 분류 미상의 대형 침식체!","JPN":"ターゲットは前方に出現した分類未詳の大型侵食体！","ENG":"The target is a large, unclassified C.O. appearing straight ahead!","TWN":"目標是前方出沒的類別不明大型侵蝕體！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"머리로 보이는 부분을 노려! 놈의 공격은 내가 막겠다!","JPN":"頭と思われる部分を狙え！　やつの攻撃は私が食い止める！","ENG":"Shoot where you think its head is! I'll deflect its attacks!","TWN":"瞄準頭部！我來抵擋它的攻擊！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"예!","JPN":"はっ！","ENG":"Yes, ma'am!","TWN":"是！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};